    // 1. Build Adjacency Matrix
    let mut adj = vec![vec![false; n]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let mut count = 0;
    let total_subsets = 1 << n;

    // Iterate over all non-empty subsets M (masks from 1 to 2^N - 1)
    for m in 1..total_subsets {
        // 2. Check Condition 2: Sum of values is even
